import React, { useState } from 'react';

const s = {
  page: {
    minHeight: 'calc(100vh - 64px)',
    background: '#f3f4f6',
    padding: '40px 24px',
  },
  container: {
    maxWidth: 1280,
    margin: '0 auto',
  },
  title: {
    fontSize: 28,
    fontWeight: 700,
    color: '#111827',
    marginBottom: 24,
  },
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: 20,
    marginTop: 20,
  },
  companyCard: {
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 10,
    padding: 24,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
    transition: 'all 0.2s',
    cursor: 'pointer',
    ':hover': {
      boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    },
  },
  companyIcon: {
    fontSize: 40,
    marginBottom: 12,
  },
  companyName: {
    fontSize: 16,
    fontWeight: 600,
    color: '#1f2937',
    marginBottom: 8,
  },
  companyDesc: {
    fontSize: 12,
    color: '#6b7280',
    marginBottom: 16,
  },
  badge: {
    display: 'inline-block',
    background: '#eff6ff',
    color: '#1e40af',
    padding: '4px 10px',
    borderRadius: 4,
    fontSize: 11,
    fontWeight: 500,
    marginRight: 8,
    marginBottom: 8,
  },
  section: {
    background: '#fff',
    border: '1px solid #e5e7eb',
    borderRadius: 10,
    padding: 24,
    marginBottom: 24,
    boxShadow: '0 1px 3px rgba(0,0,0,0.07)',
  },
  sectionTitle: {
    fontSize: 16,
    fontWeight: 600,
    color: '#1f2937',
    marginBottom: 16,
  },
  button: {
    width: '100%',
    padding: '12px',
    marginTop: 16,
    background: '#e8440a',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 14,
    fontWeight: 600,
    cursor: 'pointer',
    transition: 'background 0.2s',
  },
  input: {
    width: '100%',
    padding: '10px 12px',
    border: '1px solid #d1d5db',
    borderRadius: 6,
    fontSize: 13,
    fontFamily: 'Inter, sans-serif',
    marginBottom: 12,
  },
  textarea: {
    width: '100%',
    padding: '10px 12px',
    border: '1px solid #d1d5db',
    borderRadius: 6,
    fontSize: 13,
    fontFamily: 'Inter, sans-serif',
    minHeight: 80,
    marginBottom: 12,
    resize: 'vertical',
  },
  emptyState: {
    textAlign: 'center',
    padding: '60px 20px',
    color: '#9ca3af',
  },
};

export default function Companies() {
  const [companies, setCompanies] = useState([
    {
      id: 1,
      name: 'TechCorp',
      logo: '💻',
      description: 'Leading software development company',
      recruiters: 5,
      openings: 12,
      registered: true,
    },
    {
      id: 2,
      name: 'DataFlow',
      logo: '📊',
      description: 'Big data and analytics solutions',
      recruiters: 3,
      openings: 8,
      registered: true,
    },
    {
      id: 3,
      name: 'CloudScale',
      logo: '☁️',
      description: 'Cloud infrastructure services',
      recruiters: 2,
      openings: 5,
      registered: true,
    },
  ]);

  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    description: '',
    contactEmail: '',
    location: '',
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleRegister = (e) => {
    e.preventDefault();
    if (formData.name && formData.description) {
      const newCompany = {
        id: companies.length + 1,
        name: formData.name,
        logo: '🏢',
        description: formData.description,
        recruiters: 1,
        openings: 0,
        registered: true,
      };
      setCompanies([...companies, newCompany]);
      setFormData({ name: '', description: '', contactEmail: '', location: '' });
      setShowForm(false);
    }
  };

  return (
    <div style={s.page}>
      <div style={s.container}>
        <h1 style={s.title}>🏢 Companies</h1>

        <div style={s.section}>
          <div style={s.sectionTitle}>📋 Registered Companies ({companies.length})</div>
          <div style={s.grid}>
            {companies.map(company => (
              <div key={company.id} style={s.companyCard}>
                <div style={s.companyIcon}>{company.logo}</div>
                <div style={s.companyName}>{company.name}</div>
                <p style={s.companyDesc}>{company.description}</p>
                <div>
                  <span style={s.badge}>👥 {company.recruiters} Recruiters</span>
                  <br />
                  <span style={s.badge}>📂 {company.openings} Openings</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={s.section}>
          <div style={s.sectionTitle}>
            ➕ Register New Company
            <button
              onClick={() => setShowForm(!showForm)}
              style={{
                float: 'right',
                padding: '6px 12px',
                background: '#2563eb',
                color: '#fff',
                border: 'none',
                borderRadius: 6,
                fontSize: 12,
                fontWeight: 600,
                cursor: 'pointer',
              }}
            >
              {showForm ? 'Cancel' : 'Add Company'}
            </button>
          </div>

          {showForm && (
            <form onSubmit={handleRegister}>
              <label style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 4, display: 'block' }}>
                Company Name *
              </label>
              <input
                style={s.input}
                type="text"
                name="name"
                placeholder="e.g. Acme Tech"
                value={formData.name}
                onChange={handleInputChange}
                required
              />

              <label style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 4, display: 'block' }}>
                Description *
              </label>
              <textarea
                style={s.textarea}
                name="description"
                placeholder="What does your company do?"
                value={formData.description}
                onChange={handleInputChange}
                required
              />

              <label style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 4, display: 'block' }}>
                Contact Email
              </label>
              <input
                style={s.input}
                type="email"
                name="contactEmail"
                placeholder="contact@company.com"
                value={formData.contactEmail}
                onChange={handleInputChange}
              />

              <label style={{ fontSize: 12, fontWeight: 600, color: '#374151', marginBottom: 4, display: 'block' }}>
                Location
              </label>
              <input
                style={s.input}
                type="text"
                name="location"
                placeholder="e.g. San Francisco, CA"
                value={formData.location}
                onChange={handleInputChange}
              />

              <button type="submit" style={s.button}>
                ✓ Register Company
              </button>
            </form>
          )}
        </div>

        <div style={s.section}>
          <div style={s.sectionTitle}>📖 Company Management</div>
          <p style={{ fontSize: 14, color: '#4b5563', lineHeight: 1.8 }}>
            <strong>For Company Admins:</strong> Register your company to start recruiting. Once registered, 
            you can invite recruiters to your account, manage job openings, and access detailed candidate 
            insights. Each company can have multiple recruiters and manage unlimited job positions.
          </p>
          <p style={{ fontSize: 14, color: '#4b5563', lineHeight: 1.8, marginTop: 12 }}>
            <strong>Features:</strong> Multi-recruiter support, candidate pool management, role-based access control, 
            analytics dashboard, and integration with existing HR systems.
          </p>
        </div>
      </div>
    </div>
  );
}
